INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-20518958', '안양예술공원 이용 시 3곳 주차장 중 "예술공원로 131번길 7" 주차장(도보 10~15분)이 가장 진입이 빠릅니다. 수목원 입구 인근 주차장은 매우 작고 1시간 이상 대기가 필요하므로 주의가 필요합니다.', '대부분 유료이나 일부 무료 비포장 주차장(석수동 839)이 있습니다.', '오전 9시 이전 방문을 권장합니다. 수목원 입구 가까운 주차장은 높은 대기를 각오해야 합니다. 도보 10~15분 떨어진 주차장(예술공원로 131번길 7)이 입차가 빠릅니다.', NULL, datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
