INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-27104439', '해양광장 공영주차장은 넓은 주차공간을 보유하고 있습니다. 여름철(7월~8월) 물놀이터 운영 시간대에 방문객이 증가합니다.', NULL, NULL, NULL, datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
